import numpy as np

class KMeansPlusPlus:
    def __init__(self, n_clusters: int, max_iter: int = 300, random_state: int = 42):
        self.K = n_clusters
        self.max_iter = max_iter
        self.random_state = random_state
        self.centers_ = None

    def _pairwise_sq_dists(self, X, centers):
        """Compute squared distances from each X to each center. Returns (N, K)."""
        X2 = np.sum(X ** 2, axis=1, keepdims=True)
        C2 = np.sum(centers ** 2, axis=1)
        cross = X @ centers.T
        return np.maximum(X2 + C2 - 2 * cross, 0.0)

    def _init_centers(self, X: np.ndarray) -> np.ndarray:
        rng = np.random.RandomState(self.random_state)
        N = X.shape[0]
        # Step 1: choose first center uniformly
        centers = [X[rng.randint(N)]]

        for _ in range(1, self.K):
            # Step 2: D(x)^2 = min sq dist to any chosen center
            sq_dists = self._pairwise_sq_dists(X, np.array(centers))  # (N, chosen)
            D2 = sq_dists.min(axis=1)  # (N,)
            # Sample proportional to D^2
            probs = D2 / D2.sum()
            idx = rng.choice(N, p=probs)
            centers.append(X[idx])
        return np.array(centers)

    def fit(self, X: np.ndarray) -> None:
        self.centers_ = self._init_centers(X)

        for _ in range(self.max_iter):
            # Assignment step
            sq_dists = self._pairwise_sq_dists(X, self.centers_)  # (N, K)
            labels = np.argmin(sq_dists, axis=1)  # (N,)
            # Update step
            new_centers = np.array([
                X[labels == k].mean(axis=0) if (labels == k).sum() > 0 else self.centers_[k]
                for k in range(self.K)
            ])
            if np.allclose(new_centers, self.centers_):
                break
            self.centers_ = new_centers
        self.labels_ = labels

    def predict(self, X: np.ndarray) -> np.ndarray:
        sq_dists = self._pairwise_sq_dists(X, self.centers_)
        return np.argmin(sq_dists, axis=1)

