import torch

class KMeansPlusPlusTorch:
    def __init__(self, n_clusters: int, max_iter: int = 300, random_state: int = 42):
        self.K = n_clusters
        self.max_iter = max_iter
        self.random_state = random_state
        self.centers_ = None

    def _pairwise_sq_dists(self, X: torch.Tensor, centers: torch.Tensor) -> torch.Tensor:
        return torch.cdist(X, centers).pow(2)

    def _init_centers(self, X: torch.Tensor) -> torch.Tensor:
        gen = torch.Generator().manual_seed(self.random_state)
        N = X.shape[0]
        idx = torch.randint(N, (1,), generator=gen).item()
        centers = [X[idx]]

        for _ in range(1, self.K):
            sq_dists = self._pairwise_sq_dists(X, torch.stack(centers))
            D2 = sq_dists.min(dim=1).values
            probs = D2 / D2.sum()
            idx = torch.multinomial(probs, 1, generator=gen).item()
            centers.append(X[idx])
        return torch.stack(centers)

    def fit(self, X: torch.Tensor) -> None:
        X = X.float()
        self.centers_ = self._init_centers(X)

        for _ in range(self.max_iter):
            sq_dists = self._pairwise_sq_dists(X, self.centers_)
            labels = torch.argmin(sq_dists, dim=1)
            new_centers = torch.stack([
                X[labels == k].mean(dim=0) if (labels == k).sum() > 0 else self.centers_[k]
                for k in range(self.K)
            ])
            if torch.allclose(new_centers, self.centers_):
                break
            self.centers_ = new_centers
        self.labels_ = labels

    def predict(self, X: torch.Tensor) -> torch.Tensor:
        sq_dists = self._pairwise_sq_dists(X.float(), self.centers_)
        return torch.argmin(sq_dists, dim=1)
